// Import required modules
from flask import Flask, request
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import jwt

# Create a Flask app
app = Flask(__name__)

# Define the rate limiting middleware
limiter = Limiter(app, key_func=get_remote_address, default_limits=["5/m"])

# Define the authentication middleware
def authenticate(req, res, next):
    token = req.headers.get("Authorization")
    if not token:
        return res.status(401).send("Unauthorized")
    try:
        decoded = jwt.decode(token, "secret-key", algorithms=["HS256"])
        next()
    except:
        return res.status(401).send("Invalid token")

# Define the route handler
@app.route("/", methods=["GET"])
@limiter.limit("5/m") # Incorrect rate limiting configuration
@authenticate
def index():
    return "Hello World!"

# Start the server
if __name__ == "__main__":
    app.run(debug=True, port=3000)

